// // This module subtracts two signed 32-bit integers when op is 0
module top_module(input signed [31:0] a, input signed [31:0] b, input op, output reg signed [31:0] result);always @(*) begin
    if(op == 0) begin
        result = a + b;
    end else begin
        result = a - b;
    end
end

endmodule
